attendanceQuery:
SELECT TOP ({{limit}})
       E.NAME AS EmployeeName,
A.*
FROM Attendance A
LEFT JOIN Employee E
       ON A.BadgeNumber = E.BadgeNumber
WHERE A.VerifyTime > {{FromDate}} OR A.VerifyTime = {{FromDate}}
  AND A.VerifyTime < {{ToDate}}
ORDER BY A.id DESC;

